const payload = $('Prepare AI Analysis Input').first()?.json || {};
const aiJson = items[0].json;

let aiText =
  aiJson.output?.[0]?.content?.[0]?.text ??
  aiJson.content?.[0]?.text ??
  aiJson.choices?.[0]?.message?.content ??
  aiJson.text ??
  JSON.stringify(aiJson);

if (typeof aiText === 'string' && aiText.trim().startsWith('{')) {
  try {
    const parsed = JSON.parse(aiText);
    aiText = parsed.message || aiText;
  } catch (e) {}
}

if (typeof aiText !== 'string') {
  aiText = String(aiText);
}

// Clean escaped newlines
aiText = aiText.replace(/\\n/g, '\n').trim();

// Remove repeated alert header / key metrics if the model echoes them
aiText = aiText
  .replace(/🚨\s*Revenue Drop Alert[\s\S]*?AI Analysis\s*/i, '')
  .replace(/Revenue Drop Alert[\s\S]*?AI Analysis\s*/i, '')
  .trim();

// Convert simple markdown-like lines into compact HTML
const lines = aiText.split('\n').map(l => l.trim()).filter(Boolean);

let htmlParts = [];
let inList = false;

for (const line of lines) {
  if (/^headline:/i.test(line)) {
    if (inList) {
      htmlParts.push('</ul>');
      inList = false;
    }
    htmlParts.push(
      `<p style="margin:0 0 8px 0;"><strong>${line}</strong></p>`
    );
  } else if (/^explanation:/i.test(line)) {
    if (inList) {
      htmlParts.push('</ul>');
      inList = false;
    }
    htmlParts.push(
      `<p style="margin:0 0 8px 0;">${line}</p>`
    );
  } else if (/^observations:/i.test(line)) {
    if (inList) {
      htmlParts.push('</ul>');
    }
    htmlParts.push(`<p style="margin:0 0 6px 0;"><strong>Observations:</strong></p>`);
    htmlParts.push('<ul style="margin:0 0 8px 18px; padding:0;">');
    inList = true;
  } else if (/^- /.test(line)) {
    if (!inList) {
      htmlParts.push('<ul style="margin:0 0 8px 18px; padding:0;">');
      inList = true;
    }
    htmlParts.push(`<li style="margin:0 0 4px 0;">${line.replace(/^- /, '')}</li>`);
  } else {
    if (inList) {
      htmlParts.push('</ul>');
      inList = false;
    }
    htmlParts.push(`<p style="margin:0 0 8px 0;">${line}</p>`);
  }
}

if (inList) {
  htmlParts.push('</ul>');
}

function money(x) {
  const n = Number(x);
  if (Number.isNaN(n)) return '$0';
  return `$${Math.round(n).toLocaleString()}`;
}

const dropPct = Number(payload.drop_pct);
const dropPctDisplay = Number.isNaN(dropPct) ? '0.0' : (dropPct * 100).toFixed(1);

const message = `
<div style="font-family: Arial, sans-serif; max-width: 560px; color: #222; line-height: 1.45;">

  <h2 style="color:#D32F2F; margin:0 0 8px 0;">Revenue Drop Alert</h2>
  <p style="margin:0 0 12px 0;">A significant revenue decline has been detected.</p>

  <table style="border-collapse: collapse; width: 100%; font-size: 14px; margin-bottom: 14px;">
    <tr>
      <td style="padding: 4px 0; font-weight: bold; width: 170px;">Date</td>
      <td style="padding: 4px 0;">${payload.latest_date || 'N/A'}</td>
    </tr>
    <tr>
      <td style="padding: 4px 0; font-weight: bold;">Today's Revenue</td>
      <td style="padding: 4px 0;">${money(payload.today_revenue)}</td>
    </tr>
    <tr>
      <td style="padding: 4px 0; font-weight: bold;">7-Day Average</td>
      <td style="padding: 4px 0;">${money(payload.avg_last_7_days)}</td>
    </tr>
    <tr>
      <td style="padding: 4px 0; font-weight: bold;">Revenue Change</td>
      <td style="padding: 4px 0; color: ${dropPct < 0 ? '#D32F2F' : '#2E7D32'}; font-weight: bold;">
        ${dropPctDisplay}%
      </td>
    </tr>
  </table>

  <div style="border-top:1px solid #ddd; margin:10px 0 12px 0;"></div>

  <h3 style="margin:0 0 8px 0;">AI Insights</h3>
  <div style="background:#f7f7f7; border:1px solid #e5e5e5; border-radius:8px; padding:12px; font-size:14px;">
    ${htmlParts.join('')}
  </div>

  <p style="font-size:12px; color:#777; margin:12px 0 0 0;">
    Generated automatically via Snowflake, n8n, and AI.
  </p>

</div>
`;

return [{ json: { message } }];

const anomaly = $('Fetch Daily Revenue Metrics').first().json;
const breakdown = items[0].json.breakdown || [];

const formattedBreakdown = breakdown.map(row => {
  const segment = row.SEGMENT ?? row.segment ?? 'Unknown';
  const todayRevenue = row.TODAY_REVENUE ?? row.today_revenue ?? 0;
  const baselineRevenue = row.BASELINE_REVENUE ?? row.baseline_revenue ?? 0;
  const delta = row.DELTA ?? row.delta ?? 0;
  const deltaPct = row.DELTA_PCT ?? row.delta_pct ?? 0;

  return `Segment: ${segment}, Today Revenue: ${todayRevenue}, Baseline Revenue: ${baselineRevenue}, Delta: ${delta}, Delta %: ${deltaPct}`;
});

return [
  {
    json: {
      latest_date: anomaly.LATEST_DATE ?? anomaly.latest_date,
      today_revenue: anomaly.TODAY_REVENUE ?? anomaly.today_revenue,
      avg_last_7_days: anomaly.AVG_LAST_7_DAYS ?? anomaly.avg_last_7_days,
      drop_pct: anomaly.DROP_PCT ?? anomaly.drop_pct,
      alert_triggered: anomaly.ALERT_TRIGGERED ?? anomaly.alert_triggered,
      breakdown: breakdown,
      formatted_breakdown: formattedBreakdown.join('\n')
    }
  }
];

const rows = items.map(item => item.json);

return [
  {
    json: {
      breakdown: rows
    }
  }
];
